import 'package:pharmacy_wms/Models/materialModel.dart';class AlertModel {  final String id;  final String alertType; 
final String message;  final MaterialModel? material;  final DateTime createdAt;  AlertModel({    required this.id,    required this.alertType,    required this.message,    this.material,    required this.createdAt,  });  factory AlertModel.fromJson(Map<String, dynamic> json) {    return AlertModel(      id: json['id'],      alertType: json['alert_type'],      message: json['message'],      material: json['material'] != null          ? MaterialModel.fromJson(json['material'])          : null,      createdAt: DateTime.parse(json['created_at']),    );  }  Map<String, dynamic> toJson() {    return {      'id': id,      'alert_type': alertType,      'message': message,      'material': material?.toJson(),      'created_at': createdAt.toIso8601String(),    };  }}